var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈은…….","JPN":"貴様は……","ENG":"You are...","TWN":"你這傢伙……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"과연, 애송이 몸에 남아있던 마창의 잔여물이 환영으로 구현된 건가?","JPN":"なるほど、小娘の体に残っていた魔槍の残滓が幻影として具現化されたのか？","ENG":"I see, so the remnants of the evil spear in that kid's body manifested as an illusion?","TWN":"果然，留在丫頭體內的魔槍殘留物化作幻影了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"죽어서까지 계집 하나 지키려 들다니. 이것 참 눈물나는 가족애로군.","JPN":"死んでまで小娘を守ろうとするとは。涙ぐましい家族愛だ。","ENG":"Even in death, still trying to protect some girl? Truly heartwarming familial devotion.","TWN":"死了還要保護一個小丫頭。真是令人感動的親情啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈의 허튼 수작질이 그림자 때 묻혀버린 이성이라도 되찾아줄 거라 믿는 건가?","JPN":"貴様の小細工が、シャドウになって埋もれてしまった理性を取り戻してくれるとでも信じているのか？","ENG":"Do you really believe your pitiful trick will somehow restore her Shadow-tainted sanity?","TWN":"你以為你的胡鬧能幫我找回被暗影污染的理智嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……닮았군.","JPN":"……似ているな。","ENG":"...You're just like him.","TWN":"真像啊。"},"stage":{"bg":"MS_903","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"허나 네놈에게는 누군가의 의무를 짊어질 책임이 없다.","JPN":"だが、貴様には誰かの義務を背負う責任がない。","ENG":"But unlike him, you carry no sense of duty to anyone.","TWN":"然而你沒有承擔他人責任的義務。"},"stage":{"bg":"MS_903","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하물며 유리한 전장을 구분하지 못하는 자는 범상하다고도 할 수 없지.","JPN":"ましてや戦場の勝ち負けを見分けられない者は平凡とも言えない。","ENG":"And someone who can't even recognize favorable ground isn't worthy of even being called ordinary.","TWN":"況且，一個分不清有利戰場的人，也無法獲得非凡的成就。"},"stage":{"bg":"MS_903","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하! 망령 따위가 내게 궤변을 늘어놓는 거냐?","JPN":"は！　亡霊ごときが俺に詭弁を弄するか？","ENG":"Hah! A ghost dares lecture me with riddles?","TWN":"下！區區亡靈也敢對我胡言亂語？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아니, 내가 할 말은 하나뿐이다.","JPN":"いや、私の言いたいことは一つだけだ。","ENG":"I only have one thing to say.","TWN":"不，我只有一句話要說。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"설령 네놈이 그분과 같은 <color=#ffd34c>운명</color>을 지녔다 한들…….","JPN":"たとえ貴様があの方のような<color=#ffd34c>運命</color>を持っているとしても……","ENG":"Even if you share the same <color=#ffd34c>fate</color> as he did...","TWN":"即便你擁有與那位相同的<color=#ffd34c>命運</color>……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"짊어진 자로서의 자각을 잃고 힘에 도취되는 순간, 결코 고귀한 존재가 될 수 없어.","JPN":"背負った者としての自覚を忘れ、力に溺れた瞬間、決して高貴な存在にはなれない。","ENG":"The moment you lose awareness of the burden you bear and get drunk on your own power, you'll never be noble.","TWN":"一旦失去作為承擔者的自覺，沉醉於力量之中，就絕不可能成為高貴的存在。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"지루한 입싸움은 끝내지.","JPN":"つまらない口喧嘩はここまでだ。","ENG":"Enough of this boring talk.","TWN":"無聊的口角該結束了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"마왕의 죽음에도 클리파의 잔재가 제 스스로 영향을 발휘한 이유는 알 수 없으나.","JPN":"魔王が死んだにも関わらずクリファの残滓が自ら影響力を発揮した理由はわからないが。","ENG":"I don't know why the remnants of Qlipha still stir despite the Demon Lord's death...","TWN":"雖然不知道即使在魔王死後，逆卡巴拉的殘餘為何仍能自行發揮影響。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈이 할 수 있는 건 고작해야 시간을 버는 것이다.","JPN":"貴様にできることは、たかが時間稼ぎくらいだ。","ENG":"All you can do is stall for time.","TWN":"你能做的不過是拖延時間罷了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"한 가지 착각하고 있군, 네놈은.","JPN":"貴様は一つ勘違いをしている。","ENG":"You're mistaken about one thing.","TWN":"你有一個誤會。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지금의 내 존재를 규정하는 건, 마왕의 힘이 아니다.","JPN":"今の私の存在を規定しているのは、魔王の力ではない。","ENG":"My current existence isn't sustained by the Demon Lord's power.","TWN":"現在定義我存在的，不是魔王的力量。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이 힘은… 설마?","JPN":"この力……まさか？","ENG":"This power... It can't be.","TWN":"這股力量是……難道？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"말했을 텐데. 유리한 전장을 구분하지 못하는 자는 범상하다고도 할 수 없다고.","JPN":"言ったはずだ。戦場の勝ち負けを見分けられない者は平凡とも言えないと。","ENG":"I told you. Someone who can't even recognize favorable ground isn't worthy of even being called ordinary.","TWN":"我已經說過了。分不清有利戰場的人，也無法獲得非凡的成就。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그 오만함은 언젠가 네 목숨을 조여오는 패착이 될 거다.","JPN":"その傲慢さはいつか貴様の首を絞めるだろう。","ENG":"That arrogance of yours will be your undoing.","TWN":"那份傲慢終將成為扼殺你生命的敗筆。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"흥. 목적을 달성했는데 굳이 번거로운 힘싸움을 할 필요야 없지.","JPN":"ふん。目的を達成したのにわざわざ面倒な戦いをする必要もない。","ENG":"Hmph. I've already achieved my goal. No need to waste effort fighting you now.","TWN":"哼。既然已經達到目的，就沒必要進行麻煩的爭鬥了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"불필요한 싸움의 승리라도 원한다면 기꺼이 내어주마, 패배한 세계의 망령이여.","JPN":"不要な戦いの勝利を欲するなら、喜んで負けてやろう、敗北した世界の亡霊よ。","ENG":"But if you really want a hollow victory, I'll leave you that. Take it, ghost of a failed world.","TWN":"即使是不必要的戰鬥勝利，如果你想要，我也願意給予你，失敗世界的亡靈啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"사라졌다…?","JPN":"消えた……？","ENG":"He vanished...?","TWN":"消失了…？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"역시 루크레시아의 부활의 지팡이인가.","JPN":"やはりルクレシアの復活の杖か。","ENG":"So it really was Lucrecia's Staff of Resurrection.","TWN":"果然是露可蕾西亞的復活之杖嗎。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그녀의 힘의 잔재가 깃들어 있다 한들 제법 억지스러운 사용 방법을 택했군.","JPN":"彼女の力の残滓が宿っているとしても、無理がある使用方法を選んだものだ。","ENG":"Even if it holds a trace of her power, the way he used it was nothing but brute force.","TWN":"即便她的力量殘留在其中，也選擇了相當勉強的使用方法啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"정말… 알렌 경이십니까?","JPN":"本当に……アレン卿ですか？","ENG":"Are you really... Sir Allen?","TWN":"真的是……艾倫卿嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"기억의 편린으로 존재를 규명할 수 있다면 그렇겠지.","JPN":"記憶の片鱗で存在を糾明できるものなら、そうなるだろう。","ENG":"If a fragment of memory can define someone's existence, then yes.","TWN":"如果能通過記憶的碎片來確認存在，那就好了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"자네가 이것을 악몽으로 여긴다면 그 또한 정답일 테고.","JPN":"君がこれを悪夢だと思っているなら、それもまた正解だ。","ENG":"If you want to believe this is just a nightmare, then that's fine too.","TWN":"如果你把這視為惡夢，那也是正確的答案。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 말씀은…….","JPN":"つまり……","ENG":"That means...","TWN":"那句話是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아직 시간이 있으니 너무 서두를 필요는 없네.","JPN":"まだ時間がある。そう急ぐ必要はない。","ENG":"No need to rush. We still have time.","TWN":"還有時間，所以沒必要太著急。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"돌아가기 전에 잠시 걷겠나? 마침 이 근방은 산책하기 좋은 길이라네.","JPN":"戻る前に少し歩かないか？　ちょうどこの辺りは、散歩するのにもってこいなんだ。","ENG":"How about a walk before we head back? The path nearby is perfect for it.","TWN":"回去之前要一起走走嗎？正好這附近有適合散步的路。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저… 알렌 경?","JPN":"あの……アレン卿？","ENG":"Um... Sir Allen?","TWN":"我……和你嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저흰 지금 어디로 가는 겁니까?","JPN":"私たちは今どこに向かっているのですか？","ENG":"Where are we going?","TWN":"我們現在要去哪？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"방금 전 싸움. 나와 대련할 때보다 검이 무거워 보이더군.","JPN":"さっきの戦闘。私と手合わせをした時より剣が重く見えたのだが。","ENG":"During that fight just now, your sword looked heavier than when we last sparred.","TWN":"就在剛才的戰鬥中。看起來你的劍比和我對練時要沉重。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고민거리가 있다면 얘기해 보게.","JPN":"悩みがあるなら言いたまえ。","ENG":"You can talk to me if you have a problem.","TWN":"有什麼煩惱的話可以說出來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……상담도 전술학의 일부란 사실은 처음 알았습니다.","JPN":"……相談も戦術学の一部だとは知りませんでした。","ENG":"...I didn't know consultation was part of strategy.","TWN":"……原來心理諮商也是戰術學的一部份嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"학생들의 고충을 상담해 주는 건 교사가 당연히 해야 할 일이라네.","JPN":"学生の悩みを聞くのは教師として当然のことだ。","ENG":"It's only natural that I want to help my students with their problems as their mentor.","TWN":"聆聽學生的煩惱是老師應該做的吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 조디악 나이츠의 단장이라면, 없는 시간을 쪼개서라도 이야기를 나누고 싶군.","JPN":"しかもそれがゾディアックナイツの団長ともなると、暇を作ってでも話を聞いてみたいと思うものさ。","ENG":"Also, you're the captain of the Zodiac Knights. I can always make time for you.","TWN":"更何況你還是十二宮騎士團的團長，就算沒時間我也要擠出時間來聽你說。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그건…… 그레이스 경께서 기사단의 설립자이기 때문입니까?","JPN":"それは……グレース卿が騎士団の設立者だからですか？","ENG":"Is... it because Dame Grace founded the Order?","TWN":"那是因為……葛瑞絲小姐是騎士團的創始人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"분명, 그것만은 아니겠지.","JPN":"きっと、それだけではないだろう。","ENG":"That's part of it, but not the whole reason.","TWN":"顯然，不僅僅是這樣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"악몽 때문입니다.","JPN":"悪夢のせいです。","ENG":"My nightmares.","TWN":"是因為做惡夢的關係。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"악몽이라…….","JPN":"悪夢か……","ENG":"Nightmares...","TWN":"惡夢……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자세히 얘기해 줄 수 있겠나?","JPN":"詳しく聞かせてもらえるかな？","ENG":"Could you elaborate on that?","TWN":"你願意說給我聽嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"네. 아주 먼 옛날의, 아름다운 제국의 기사들이 차례차례 쓰러져 가는 광경이었죠.","JPN":"はい。遠い昔の、美しい帝国の騎士たちが次々と倒れていく光景でした。","ENG":"Yes. It was a vision of long ago, where the noble knights of a beautiful empire fell one by one.","TWN":"我夢到有一座很古老的美麗帝國，騎士們一個接一個地倒下的景象。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그곳에서 저는 검을 들고 있음에도…… 우두커니 서 있어야 했습니다.","JPN":"そこで私は剣を手にしていて……ただ呆然と立っていました。","ENG":"I stood there with a sword in my hand... unable to move.","TWN":"在那裡，即使我握著劍……也只能呆呆地站著。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"꿈 속의 동료들이 사악하고 거대한 무언가와 맞서는 모습을 지켜만 보면서.","JPN":"夢の中の仲間たちが邪悪で巨大な何かと戦う姿を、ただ見ていることしかできずに。","ENG":"Helplessly watching my comrades fight something vast and evil in a dream.","TWN":"夢中的夥伴們正在與邪惡而巨大的東西對抗，而我只能旁觀。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 광경을 보고, 포기하고 싶었나?","JPN":"その光景を見て、諦めたくなったか？","ENG":"Did seeing that make you want to give up?","TWN":"看到那種場景後，你想放棄嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"포기하면 무언가 달라질까요?","JPN":"諦めたら何かが変わるのでしょうか？","ENG":"Would giving up have changed anything?","TWN":"放棄的話會有什麼改變嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"적어도 괴롭지는 않겠지.","JPN":"少なくとも辛くはないだろう。","ENG":"At least it wouldn't hurt as much.","TWN":"至少不會痛苦吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그게 옳은 선택일까요?","JPN":"それが正しい選択でしょうか？","ENG":"But would that be the right thing to do?","TWN":"這是正確的選擇嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"틀렸다고 나무라는 사람은 없을 거다.","JPN":"間違ったと責める人はいないはずだ。","ENG":"No one would blame you for it.","TWN":"沒有人會責怪你錯了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……그럼에도.","JPN":"……でも。","ENG":"...Even so.","TWN":"……儘管如此。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"제게 포기하라는 말은 하지 않으시는군요.","JPN":"私に諦めろとは言わないのですね。","ENG":"You still won't tell me to give up.","TWN":"你並沒有讓我放棄呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"알고 있나? 모든 이야기의 시작과 끝은 때론 동일하다고 하지.","JPN":"知っているか？　すべての物語の始まりと終わりは、時に同じだという。","ENG":"Did you know? They say every story begins and ends in the same place.","TWN":"你知道嗎？所有故事的開始和結局有時是相同的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네가 진정한 이야기의 종착역에 다다르고자 한다면, 앞이 아닌 뒤를 돌아봐야 할 걸세.","JPN":"君が物語の本当の終着駅にたどり着こうとするなら、前ではなく後ろを振り返ってみることだ。","ENG":"If you truly want to reach the end of your story, maybe you need to stop looking ahead and look behind.","TWN":"如果你想要到達真正故事的終點，就應該回頭看看，而不是向前看。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그게 무슨 말씀이시죠?","JPN":"それはどういうことですか？","ENG":"What do you mean by that?","TWN":"這是什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"내게 어디로 향하고 있는지 묻지 않았나.","JPN":"私にどこに向かっているのかと聞いたではないか？","ENG":"You asked me where we were going, didn't you?","TWN":"你不是問我要去哪裡嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이것이 나의 대답일세.","JPN":"これが私の答えさ。","ENG":"That's my answer.","TWN":"這就是我的回答。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"낯익은 풍경이 시야에 들어오자 잊고 있던 꽃내음이 코끝을 스친다.","JPN":"見慣れた景色が視野に入ると、忘れていた花の香が鼻をくすぐる。","ENG":"As familiar scenery came into view, a forgotten scent of flowers brushed past my nose.","TWN":"熟悉的風景映入眼簾，遺忘已久的花香撲鼻而來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"멀리 아른거리는 작은 마을의 풍경이 솟아오른 나무 그림자에 가려져 흐릿하게 보일 때면.","JPN":"遠くにちらちらと見えていた小さな村の風景が、そびえ立つ木々の影に隠れておぼろげになると。","ENG":"When the shadow of a towering tree blurred the view of a tiny village shimmering in the distance...","TWN":"遠處隱約可見的小村莊景色被高聳的樹影遮擋，顯得模糊不清。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"이윽고, 갈 곳 없는 아이에게 손짓하던 여인의 모습 뒤로.","JPN":"やがて、居場所のない子どもに手招きしている女性の後ろに。","ENG":"And just beyond the woman who once reached out to a lost child...","TWN":"最終，在向無處可去的孩子招手的女人身後。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"잊힐 리 없는 추억이 푸른 꽃으로 피어나, 밤이 오지 않은 하늘 아래 별빛을 일구었다.","JPN":"忘れられるはずのない思い出が青い花として咲き、夜の来ない空の下で星の光を輝かせた。","ENG":"A memory too vivid to forget blooms into a blue flower, cultivating starlight beneath a sky untouched by night.","TWN":"難以忘懷的回憶綻放成藍色的花朵，在未曾降臨夜晚的天空下，繁星點點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……기억하고 있습니다.","JPN":"……覚えています。","ENG":"...I remember this place.","TWN":"……是的。我還記得。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여긴, 알렌 경과 처음 만난 곳이군요.","JPN":"ここは、アレン卿と最初に出会った場所ですね。","ENG":"This is where I first met you, Sir Allen.","TWN":"這裡是我第一次遇見艾倫卿的地方。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그래. 그때 이후로 마을에 철부지 둘이 늘었지.","JPN":"ああ。あの時以来、村には2人の世間知らずが加わった。","ENG":"That's right. After that, this village had two more troublemakers running around.","TWN":"是啊。從那時候起，村子裡就多了兩個小淘氣。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지금 생각하면 어느 쪽이든 오지랖이었군.","JPN":"今思えば、どっちにせよ余計なお世話だったな。","ENG":"Looking back, we were both a bit too nosy for our own good.","TWN":"現在想想，無論哪一邊都是多管閒事啊。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"역시, 제가 아직 악몽 속에 갇혀 있는 걸까요?","JPN":"やはり、私はまだ悪夢の中に閉じ込められているのでしょうか？","ENG":"Then, am I still trapped in that nightmare?","TWN":"果然，我還被困在惡夢中嗎？"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"별의 인도자는 낙오자였고 패배자였다.","JPN":"星の導き手は落ちこぼれで、敗北者だった。","ENG":"The Star Guide was a failure and a loser.","TWN":"星之引導者曾經是落伍者和失敗者。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그녀가 만든 별의 무구는 멸망을 막는데 조금도 기여하지 못했어.","JPN":"彼女が作った星の武具は滅亡を止めるのに少しも役に立たなかった。","ENG":"Her Star Armament did not contribute at all to saving the world from damnation.","TWN":"她製作的星之武具在阻止滅亡時一點貢獻都沒有。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 그녀는 또한, 고향에 비해 낙후되었던 과거의 이 세계를 보고 결단을 내렸지.","JPN":"だが彼女は故郷に比べると立ち遅れていた、過去のこの世界を見て決心した。","ENG":"And yet, after seeing how backward this world was compared to her own, she made a choice.","TWN":"但是她也在看到比自己的故鄉落後太多的這個世界之後，做出了某些決定。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"언젠가 이곳에도 닥칠 멸망에 대비할 수 있는 희망을…….","JPN":"いつかこの世界にも迫るであろう滅亡に備えることができるよう、希望を……","ENG":"Maybe that's why she planted hope for the future...","TWN":"希望有一天能為即將降臨此地的毀滅做好準備……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"어두운 밤에 길 잃고 헤매는 이들을 인도해 줄 별빛을 남기기로.","JPN":"闇夜で道に迷っている者たちを導く星の光を残そうと。","ENG":"She left the starlight to guide the lost back to the right track.","TWN":"在黑暗的夜晚，為迷路的人留下指引的星光。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그래. 마지막 순간 완성되지 못한 채 전해져 내려온 <color=#ffd34c>버고 소드</color>.","JPN":"そうだ。最後の瞬間、完成しないまま受け継がれてきた<color=#ffd34c>ヴァルゴソード</color>。","ENG":"Yes. The <color=#ffd34c>Virgo Sword</color>, passed down incomplete at the end.","TWN":"是啊。傳承至今卻未能在最後時刻完成的<color=#ffd34c>布林加夫之劍</color>。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그 안에 깃들어야 했을, 열두 무구의 마지막 별빛을.","JPN":"その中に宿っているはずだった、12武具の最後の星の光を。","ENG":"And with it, the last piece of starlight from the twelve Armaments it was meant to contain.","TWN":"那應該寄宿其中的，十二聖遺物的最後星光。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……제게 이걸 보여주시는 이유가 무엇입니까?","JPN":"……私にこれを見せてくれる理由は何ですか？","ENG":"...Why are you showing me all this?","TWN":"……你為什麼要給我看這個？"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"마왕에 의해 뒤틀린 별은 제국이 아닌 이곳으로 이어졌다.","JPN":"魔王により歪んだ星は、帝国ではなくここに繋がっていた。","ENG":"The star twisted by the Demon Lord didn't pass to the Empire. It ended up here.","TWN":"被魔王扭曲的星星連接到了這裡，而不是帝國。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그렇기에 숙명에서 벗어나 모든 걸 내려놓을 수 있었음에도, 그녀는 그러지 않았지.","JPN":"そのため、宿命から逃れ、すべてを諦めることができたはずなのに、彼女はそうしなかった。","ENG":"She could've walked away from fate. She could've let it all go. But she didn't.","TWN":"因此，即使她可以擺脫宿命，放下一切，她也沒有這樣做。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"이곳에 꽃피운 별빛이 어떤 감정으로부터 비롯된 것인지는 모르겠으나…….","JPN":"ここに咲いた星の光がどのような感情から来たものなのかはわからないが……","ENG":"I don't know what feelings that starlight bloomed from...","TWN":"不知道在這裡綻放的星光是源於何種情感……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그저, 나도 보여주고 싶었을 뿐이야.","JPN":"ただ、私も見せてあげたかったんだ。","ENG":"I just wanted to show you.","TWN":"只是，我也只是想給你看看而已。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"내가 남긴 별빛 또한 이곳에서 꽃피웠음을.","JPN":"私が残した星の光もまた、ここに咲いていると。","ENG":"That my starlight also bloomed in this place.","TWN":"我留下的星光也在這裡綻放。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……열두 무구의 마지막 별빛이라 한들, 저는 더 이상 버고 소드를 다룰 수 없습니다.","JPN":"……12武具の最後の星の光だとしても、私はもうヴァルゴソードを扱えません。","ENG":"...Even if it is the final starlight of the twelve Armaments, I can no longer wield the Virgo Sword.","TWN":"……即便那是十二聖遺物的最後星光，我也無法再使用布林加夫之劍了。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당장 이곳에는 버고 소드도 없을뿐더러…….","JPN":"今ここにヴァルゴソードもありませんし……","ENG":"It's not even here right now...","TWN":"現在這裡連布林加夫之劍都沒有……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"내 마지막 힘의 잔재가 사라지는 시점에서 자네에게 걸린 힘의 속박은 해주되겠지.","JPN":"私の最後の力の残滓が消える時点で、君にかかっていた力の束縛は消えるはずだ。","ENG":"When the last trace of my power fades, the seal binding your power will fade with it.","TWN":"在我最後的力量殘餘消失之際，束縛在你身上的力量也會解除吧。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"무엇보다 별빛을 품을 인도자의 무구라면 이미 자네 손에 들려 있지 않나.","JPN":"なにより星の光を宿す導き手の武具なら、すでに君の手にあるのではないか。","ENG":"And you're already holding an Armament that can contain starlight, aren't you? One that's passed through the hands of the Star Guide.","TWN":"更何況，若是能承載星光的引導者的武具，不正已經在你手中嗎？"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그래. 버고 소드가 아니더라도, 인도자의 손을 거친 무구가 말이야.","JPN":"そうだ。ヴァルゴソードでなくても、導き手の手を経た武具が。","ENG":"It may not be the Virgo Sword, but it's more than enough.","TWN":"是啊。即使不是布林加夫之劍，經過引導者之手的武具也是如此。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알렌 경께서는.","JPN":"アレン卿は。","ENG":"Sir Allen...","TWN":"艾倫卿。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"각오 없이 전장에 섰던 이가, 여러분의 죽음 위에 설 자격이 있다고 생각하십니까?","JPN":"覚悟なしに戦場に立った者が、皆の死の上に立つ資格があると思われますか？","ENG":"Do you really believe someone like me who came to battle with no resolve, deserves to stand on the lives of those who fell?","TWN":"沒有覺悟就站在戰場上的人，認為自己有資格站在你們的屍體上嗎？"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"오래전 전임 기사단장이 자네와 같은 이유로 마을을 찾아온 날이 있었지.","JPN":"ずいぶん前に、前騎士団長が君と同じ理由で村を訪れたことがあった。","ENG":"Long ago, a former captain of the order came to this village for the same reason you have.","TWN":"很久以前，前任騎士團長也曾因為和你一樣的原因來到村莊。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그는 자격을 갖추고 있었음에도 별빛의 수용 대신 버고 소드를 기사단에 남긴 채 떠났다.","JPN":"彼は資格を持っていたにも関わらず、星の光を受け入れる代わりに、ヴァルゴソードを騎士団に残したまま姿を消した。","ENG":"Though he was worthy, he left behind the Virgo Sword and walked away, choosing not to embrace the starlight.","TWN":"他雖然具備資格，卻選擇離開，將星光的接納留給騎士團，留下了布林加夫之劍。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당시 나는 그의 선택에 의문을 품었으나…….","JPN":"当時、私は彼の選択に疑問を抱いたが……","ENG":"At the time, I questioned his decision...","TWN":"當時我對他的選擇產生了疑問……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"이제서야 그 의미를 깨닫는군.","JPN":"今なら、分かる気がする。","ENG":"But only now do I understand what it truly meant.","TWN":"現在才領悟到其中的意義。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……저는 여러분이 생각하는 것만큼 강하지 않아요.","JPN":"……私は、皆さんが思っているほど強くありません。","ENG":"...I'm not as strong as you think I am.","TWN":"……我並不像你們想的那麼強大。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"어떤 각오로 검을 휘둘러야 하는지 자네는 알고 있네.","JPN":"どのような覚悟で剣を振るうべきか、君はわかっている。","ENG":"You know what kind of resolve it takes to wield a sword.","TWN":"你知道揮劍時需要抱有怎樣的決心嗎？"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"자네가 추구하는 <color=#ffd34c>기사도</color>가 정녕 무엇인지도 말이야.","JPN":"君が求めている<color=#ffd34c>騎士道</color>が本当は何なのかもな。","ENG":"And you know what it truly means to pursue <color=#ffd34c>chivalry</color>.","TWN":"你所追求的<color=#ffd34c>騎士精神</color>究竟是什麼呢？"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……알렌 경.","JPN":"……アレン卿。","ENG":"...Sir Allen.","TWN":"……艾倫卿。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"이제 와 사과를 건네기에는 너무 늦어버렸어.","JPN":"今更謝っても遅すぎるな。","ENG":"It's too late for apologies now.","TWN":"現在才來道歉已經太晚了。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그러니… 적어도 그녀에게 보여주었으면 하네.","JPN":"だから……せめて彼女に見せて欲しい。","ENG":"So... at the very least, show her.","TWN":"所以……至少要讓她看到。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지금까지 그녀의 선택이 틀리지 않았음을.","JPN":"彼女の選択は、間違っていなかったのだと。","ENG":"Show her that her choice wasn't wrong.","TWN":"到目前為止，她的選擇沒有錯。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그녀가 인도한 자네라는 별이 그려간 궤적이, 누구보다 찬란하게 빛나고 있음을.","JPN":"彼女に導かれた君という星が、誰よりも眩しく、輝かしい軌跡を描いたのだと。","ENG":"That the star she guided is shining brighter than anyone ever imagined.","TWN":"她所引導的名為你的星星所描繪的軌跡，比任何人都更加璀璨奪目。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그러고보니 말하는 게 늦었군.","JPN":"そういえば、言い忘れていた。","ENG":"Come to think of it, I almost forgot to say this.","TWN":"這麼說來，我說得有點晚了。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……멋진 기사가 되었구나, 에스테로사.","JPN":"……立派な騎士になったな、エステロサ。","ENG":"...You've become a fine knight, Esterosa.","TWN":"……你成為了一名出色的騎士，艾斯特洛索。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"고개를 들었을 때는 아무도 없었다.","JPN":"顔を上げたとき、そこには誰もいなかった。","ENG":"When I looked up, he was gone.","TWN":"當我抬頭時，一個人都沒有。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"처음부터, 아무도 없었다.","JPN":"最初から、誰もいなかった。","ENG":"No trace of him, like he had never been there at all.","TWN":"或許從一開始，就一個人都沒有。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어릴 적에는 침식지대 주변에 꽃이 핀 것에 의문을 품지 않았는데.","JPN":"小さい時は侵食地帯の近くに花が咲いていることをおかしいとは思わなかったが。","ENG":"Back then, I never questioned why flowers bloomed near Corrupted Areas.","TWN":"小時候，我從未對侵蝕地帶周圍開花的現象感到疑惑。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_7"},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 모든 게 당신이 남긴 별빛의 기적이었군요.","JPN":"このすべてがあなたが残した星の光の奇跡だったのですね。","ENG":"But it was all your doing. Your miracle of starlight.","TWN":"這一切都是你留下的星光奇跡啊。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_8"},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"정말로 지켜봐 주고 계셨어요.","JPN":"本当に見てくれていたのですか。","ENG":"You were watching over us all along.","TWN":"你真的在看著我呢。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_9"},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"꿈이 아닌…… 이곳에서.","JPN":"夢ではなく……ここで。","ENG":"Not in a dream... but here.","TWN":"不是夢……就在這裡。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_10"},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"그럴듯한 이유가 있다 한들, 어쩌면 도망칠 수 있는 현실에 안주하고 있었을 지도 모른다.","JPN":"それなりの理由があったとしても、もしかすると逃げ道のある現実に甘えていたのかもしれない。","ENG":"Even if I had my reasons, maybe I'd just grown comfortable hiding from reality.","TWN":"即便有合理的理由，也許我只是安於可以逃避的現實罷了。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_11"},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"그 사람과 같은 기사는 될 수 없으니 포기하라는 주변의 말에.","JPN":"あの人のような騎士にはなれないから諦めろと言う周りからの言葉に。","ENG":"When people said I'd never be a knight like him, maybe part of me was relieved.","TWN":"周圍的人說我無法成為像他那樣的騎士，勸我放棄。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_12"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"내심 안도하며 별볼일 없는 자신을 내려놓았었다.","JPN":"心の中では安心して、大したことのない自分を解放した。","ENG":"Deep down, I felt relieved letting go of myself, whom I thought amounted to nothing.","TWN":"內心鬆了口氣，放下了無足輕重的自己。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_13"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"더는, 모두의 곁에 남아있을 자격은 없다고 생각했으니까.","JPN":"もう、みんなのそばに残る資格はないと思っていたから。","ENG":"I thought I didn't deserve to stand among everyone anymore.","TWN":"因為我覺得自己已經沒有資格再留在大家身邊了。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_14"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"하지만…….","JPN":"だけど……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_15"},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별의 인도를 따르는 우린, 적들 앞에서 두려움이 없으며.","JPN":"星に導かれた私たちは、敵の前で恐れることなく。","ENG":"We follow the Star Guide and fear no enemy.","TWN":"我們遵循星之引導者，在敵人面前毫無畏懼。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_16"},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"용감하게 선을 행하여 민중을 수호한다.","JPN":"勇敢に善を尽くし、民衆を守護する。","ENG":"We act with courage and protect the people.","TWN":"勇敢地行善，守護民眾。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_17"},{"id":"L11_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"설령 우리의 창칼이 적에게 패배하여 부러지더라도.","JPN":"例えこの槍と剣が敵に敗れ折れるとしても。","ENG":"Even if our blades are broken in defeat...","TWN":"即便我們的槍刃在敵人面前折斷。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"만인을 비롯한 모든 면에서 구할 것인 바, 어떤 불평등에도 망설이지 않으니!","JPN":"万人を救わんとする志は、いかなる理不尽にも躊躇することなかれ！","ENG":"We shall save all, without hesitation, in every sense of the word!","TWN":"為了拯救所有人，在任何不平等面前都不會猶豫！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"음… 어, 그러니까…….","JPN":"うーん……えーと、えーと……","ENG":"Um... So, uh...","TWN":"嗯……呃，所以……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우리, 길 잃은 민중의 공통된 구원을 위해, 인도자께서 나에게 지혜와 가호를 주시는 대로.","JPN":"我ら、道に迷える民衆の平等なる救済のために、導き手より賜った知恵と加護のままに。","ENG":"For the common salvation of all who've lost their way, may the Guide bless me with wisdom and grace!","TWN":"為了我們這些迷途的民眾的共同救贖，願引導者賜予我智慧和庇佑！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"열두 가문이 보전한 성스러운 맹약을 따라, 이 자리에서 진실된 역할을 수행한다!","JPN":"12家門が守る聖なる盟約に従い、この場で真の役目を果たす！","ENG":"In accordance with the holy covenant upheld by the Twelve Houses, I shall fulfill my true role here and now!!","TWN":"遵循十二家族所維護的神聖盟約，在此履行真實的職責！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"좋아! 서약도 마쳤으니 우리도 어엿한 기사단인 거지?","JPN":"よし！　誓約も終わったし、私たちも立派な騎士団なんだよね？","ENG":"Okay! With the vow complete, we're official knights now, right?","TWN":"太好了！誓約也完成了，我們也算是正式的騎士團了吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"제대로 외우지도 않고 무슨 소리십니까. 리브 경이 외울 때까지 당연히 보류죠.","JPN":"ちゃんと暗記していないではないですか。リブ卿が覚えるまで当然保留です。","ENG":"Not when you haven't even memorized it properly. You're on hold until you recite it right, Dame Liv.","TWN":"沒記住就胡說什麼呢。等到莉芙記住之前當然要暫緩。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에이, 원래 이런 건 형식보다 마음가짐이 중요한 거라고.","JPN":"ええ～もともとこういうのって、形より心構えが重要なんだよ。","ENG":"Aww, come on! It's the thought that counts more than the words, you know?","TWN":"哎，這種事情心態比形式更重要啦。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부족한 부분은 다른 사람이 채워주면 그만이잖아?","JPN":"足りない部分は他の人が補ってくれたらいいじゃない。","ENG":"And besides, isn't that what comrades are for? Picking up each other's slack?","TWN":"不足的部分可以由其他人來補足，不是嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그치, 단장!","JPN":"でしょ？　団長！","ENG":"Right, Captain?","TWN":"沒錯，團長！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그래.","JPN":"そうだな。","ENG":"Right.","TWN":"好的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_18"},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……돌아가자.","JPN":"……帰ろう。","ENG":"...Let's head back.","TWN":"……回去吧。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_19"},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"내가 있어야 할 곳으로.","JPN":"私のいるべき場所へ。","ENG":"Back to where I belong.","TWN":"去我該去的地方。"},"stage":{"bg":"PRIDE_03","bgm":"THEMA_CA_CHARLOTTE_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_20"}]`);export{e as default};